namespace BgCommon;/// <summary>/// 提供时间操作相关的扩展方法与工具类./// </summary>public static partial class Extensions{    /// <summary>    /// 存储当前上下文绑定的日期时间.    /// </summary>    private static readonly AsyncLocal<DateTime?> DateTimeValue = new();    /// <summary>    /// 存储当前上下文是否使用 Utc 日期的配置.    /// </summary>    private static readonly AsyncLocal<bool?> IsUseUtcValue = new();    /// <summary>    /// Gets 获取当前日期时间.    /// </summary>    public static DateTime Now    {        get        {            // 如果手动设置了上下文时间，则优先返回            if (DateTimeValue.Value != null)            {                return DateTimeValue.Value.Value;            }            // 根据配置返回 Utc 或本地当前时间            return IsUseUtc ? DateTime.UtcNow : DateTime.Now;        }    }    /// <summary>    /// Gets a value indicating whether 是否使用Utc日期.    /// </summary>    private static bool IsUseUtc    {        get        {            return IsUseUtcValue.Value != null ? IsUseUtcValue.Value.SafeValue() : false;        }    }    /// <summary>    /// 设置当前上下文的模拟时间.    /// </summary>    /// <param name="dateTime">要设置的时间对象.</param>    public static void SetTime(DateTime? dateTime)    {        DateTimeValue.Value = dateTime;    }    /// <summary>    /// 设置当前上下文的模拟时间.    /// </summary>    /// <param name="dateTime">日期时间字符串.</param>    public static void SetTime(string dateTime)    {        SetTime(BgConvert.ToDateTimeOrNull(dateTime));    }    /// <summary>    /// 设置当前上下文是否使用 Utc 日期标志.    /// </summary>    /// <param name="isUseUtc">是否使用Utc日期,默认值: true.</param>    public static void UseUtc(bool? isUseUtc = true)    {        IsUseUtcValue.Value = isUseUtc;    }    /// <summary>    /// 重置当前上下文的时间和 Utc 配置标志.    /// </summary>    public static void Reset()    {        DateTimeValue.Value = null;        IsUseUtcValue.Value = null;    }    /// <summary>    /// 根据当前配置将日期转换为标准化日期.    /// </summary>    /// <param name="date">待处理的日期.</param>    /// <returns>标准化后的日期.</returns>    public static DateTime? Normalize(DateTime? date)    {        if (date == null)        {            return null;        }        return Normalize(date.Value);    }    /// <summary>    /// 根据当前配置将日期转换为标准化日期.    /// </summary>    /// <param name="date">待处理的日期.</param>    /// <returns>标准化后的日期.</returns>    public static DateTime Normalize(DateTime date)    {        // 如果开启了 Utc，则统一转为 UniversalTime        if (IsUseUtc)        {            return ToUniversalTime(date);        }        return ToLocalTime(date);    }    /// <summary>    /// 将日期转换为 UTC 日期.    /// </summary>    /// <param name="date">待处理的日期.</param>    /// <returns>转换后的 UTC 日期.</returns>    public static DateTime ToUniversalTime(DateTime date)    {        if (date == DateTime.MinValue)        {            return DateTime.MinValue;        }        switch (date.Kind)        {            case DateTimeKind.Local:                return date.ToUniversalTime();            case DateTimeKind.Unspecified:                // 未指定类型的视为本地时间处理                return DateTime.SpecifyKind(date, DateTimeKind.Local).ToUniversalTime();            default:                return date;        }    }    /// <summary>    /// 将日期转换为本地化日期.    /// </summary>    /// <param name="date">待处理的日期.</param>    /// <returns>转换后的本地日期.</returns>    public static DateTime ToLocalTime(DateTime date)    {        if (date == DateTime.MinValue)        {            return DateTime.MinValue;        }        switch (date.Kind)        {            case DateTimeKind.Utc:                return date.ToLocalTime();            case DateTimeKind.Unspecified:                // 未指定类型的强制指定为本地类型                return DateTime.SpecifyKind(date, DateTimeKind.Local);            default:                return date;        }    }    /// <summary>    /// 将 Utc 日期转换为本地化日期.    /// </summary>    /// <param name="date">待处理的日期.</param>    /// <returns>本地化后的日期.</returns>    public static DateTime UtcToLocalTime(DateTime date)    {        if (date == DateTime.MinValue)        {            return DateTime.MinValue;        }        if (date.Kind == DateTimeKind.Utc)        {            return date.ToLocalTime();        }        if (date.Kind == DateTimeKind.Local)        {            return date;        }        // 如果配置为使用 Utc，则将未指定的日期视为 Utc 后再转换        if (IsUseUtc)        {            return DateTime.SpecifyKind(date, DateTimeKind.Utc).ToLocalTime();        }        return date;    }    /// <summary>    /// 获取当前时间的 Unix 时间戳.    /// </summary>    /// <returns>Unix 时间戳长整型值.</returns>    public static long GetUnixTimestamp()    {        return GetUnixTimestamp(DateTime.Now);    }    /// <summary>    /// 获取指定时间的 Unix 时间戳.    /// </summary>    /// <param name="time">要转换的时间.</param>    /// <returns>Unix 时间戳长整型值.</returns>    public static long GetUnixTimestamp(DateTime time)    {        // 计算自 1970 年 1 月 1 日以来的刻度        DateTime unixEpoch = TimeZoneInfo.ConvertTime(new DateTime(1970, 1, 1), TimeZoneInfo.Local);        long elapsedTicks = (time - unixEpoch.Add(new TimeSpan(8, 0, 0))).Ticks;        return BgConvert.ToLong(elapsedTicks / TimeSpan.TicksPerSecond);    }    /// <summary>    /// 从 Unix 时间戳获取对应的日期时间.    /// </summary>    /// <param name="timestamp">Unix 时间戳.</param>    /// <returns>转换后的日期时间对象.</returns>    public static DateTime GetTimeFromUnixTimestamp(long timestamp)    {        DateTime unixEpoch = TimeZoneInfo.ConvertTime(new DateTime(1970, 1, 1), TimeZoneInfo.Local);        TimeSpan timeOffset = new TimeSpan(long.Parse(timestamp + "0000000"));        return unixEpoch.Add(timeOffset).Add(new TimeSpan(8, 0, 0));    }}